+            mission_run_id: None,
+            pane_ids: Vec::new(),
+            agent_ids: Vec::new(),
+            bead_ids: Vec::new(),
+            thread_ids: Vec::new(),
+            policy_check_ids: Vec::new(),
+            reservation_ids: Vec::new(),
+            approval_ids: Vec::new(),
+        }
+    }
+
